-- Logistics quote operations v1.
-- Scope: Saudi FBN Riyadh/RUH. Source: forwarder-standardized-saudi-fbn-riyadh-v3-20260507.xlsx.
-- This layer stores human-standardized forwarder quote details and the future operations numeric override layer.

CREATE TABLE IF NOT EXISTS `forwarder_quote_service_line` (
    `id` BIGINT NOT NULL,
    `quote_version_id` BIGINT NOT NULL,
    `quote_version_code` VARCHAR(80) NOT NULL,
    `forwarder_code` VARCHAR(50) NOT NULL,
    `service_code` VARCHAR(100) NOT NULL,
    `service_name` VARCHAR(255) NOT NULL,
    `country` VARCHAR(50) DEFAULT NULL,
    `target_platform` VARCHAR(50) DEFAULT NULL,
    `delivery_city` VARCHAR(100) DEFAULT NULL,
    `destination_node` VARCHAR(150) DEFAULT NULL,
    `transport_mode` VARCHAR(30) NOT NULL,
    `business_type` VARCHAR(80) DEFAULT NULL,
    `delivery_scope` VARCHAR(120) DEFAULT NULL,
    `origin_warehouse` VARCHAR(120) DEFAULT NULL,
    `departure_frequency` VARCHAR(120) DEFAULT NULL,
    `transit_time_text` VARCHAR(120) DEFAULT NULL,
    `transit_days_min` INT DEFAULT NULL,
    `transit_days_max` INT DEFAULT NULL,
    `active_for_mvp` BIT(1) NOT NULL DEFAULT b'1',
    `source_file_name` VARCHAR(255) DEFAULT NULL,
    `source_sheet_or_page` VARCHAR(120) DEFAULT NULL,
    `source_row_or_locator` VARCHAR(120) DEFAULT NULL,
    `source_type` VARCHAR(40) DEFAULT NULL,
    `remark` VARCHAR(1000) DEFAULT NULL,
    `created_by` BIGINT DEFAULT NULL,
    `updated_by` BIGINT DEFAULT NULL,
    `gmt_create` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    `gmt_updated` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_fq_service_line_code` (`service_code`),
    KEY `idx_fq_service_line_version` (`quote_version_id`),
    KEY `idx_fq_service_line_scope` (`transport_mode`, `target_platform`, `delivery_city`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `forwarder_quote_cargo_category` (
    `id` BIGINT NOT NULL,
    `quote_version_id` BIGINT NOT NULL,
    `quote_version_code` VARCHAR(80) NOT NULL,
    `forwarder_code` VARCHAR(50) NOT NULL,
    `service_code` VARCHAR(100) NOT NULL,
    `cargo_category_code` VARCHAR(120) NOT NULL,
    `cargo_category_name` VARCHAR(255) NOT NULL,
    `source_category_name` VARCHAR(255) DEFAULT NULL,
    `category_level_1` VARCHAR(120) DEFAULT NULL,
    `category_level_2` VARCHAR(120) DEFAULT NULL,
    `product_examples` LONGTEXT DEFAULT NULL,
    `product_keywords` LONGTEXT DEFAULT NULL,
    `electric_type` VARCHAR(80) DEFAULT NULL,
    `sensitive_tags` VARCHAR(255) DEFAULT NULL,
    `packing_policy` VARCHAR(255) DEFAULT NULL,
    `manual_confirm_required` BIT(1) NOT NULL DEFAULT b'0',
    `match_priority` INT DEFAULT NULL,
    `source_file_name` VARCHAR(255) DEFAULT NULL,
    `source_sheet_or_page` VARCHAR(120) DEFAULT NULL,
    `source_row_or_locator` VARCHAR(120) DEFAULT NULL,
    `source_type` VARCHAR(40) DEFAULT NULL,
    `remark` VARCHAR(1000) DEFAULT NULL,
    `created_by` BIGINT DEFAULT NULL,
    `updated_by` BIGINT DEFAULT NULL,
    `gmt_create` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    `gmt_updated` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_fq_cargo_category_code` (`cargo_category_code`),
    KEY `idx_fq_cargo_category_service` (`service_code`),
    KEY `idx_fq_cargo_category_version` (`quote_version_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

