CREATE TABLE IF NOT EXISTS `forwarder_quote_numeric_adjustment` (
    `id` BIGINT NOT NULL,
    `quote_version_id` BIGINT NOT NULL,
    `target_type` VARCHAR(60) NOT NULL,
    `target_id` BIGINT NOT NULL,
    `field_name` VARCHAR(80) NOT NULL,
    `original_value` DECIMAL(12,4) DEFAULT NULL,
    `adjusted_value` DECIMAL(12,4) NOT NULL,
    `currency` VARCHAR(20) DEFAULT NULL,
    `reason` VARCHAR(500) DEFAULT NULL,
    `adjustment_status` VARCHAR(40) NOT NULL DEFAULT 'ACTIVE',
    `created_by` BIGINT DEFAULT NULL,
    `updated_by` BIGINT DEFAULT NULL,
    `gmt_create` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    `gmt_updated` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_fq_numeric_adjustment_current` (`target_type`, `target_id`, `field_name`, `adjustment_status`),
    KEY `idx_fq_numeric_adjustment_version` (`quote_version_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `forwarder_quote_numeric_adjustment_log` (
    `id` BIGINT NOT NULL,
    `adjustment_id` BIGINT DEFAULT NULL,
    `quote_version_id` BIGINT NOT NULL,
    `target_type` VARCHAR(60) NOT NULL,
    `target_id` BIGINT NOT NULL,
    `field_name` VARCHAR(80) NOT NULL,
    `before_value` DECIMAL(12,4) DEFAULT NULL,
    `after_value` DECIMAL(12,4) DEFAULT NULL,
    `action_type` VARCHAR(60) NOT NULL,
    `reason` VARCHAR(500) DEFAULT NULL,
    `operated_by` BIGINT DEFAULT NULL,
    `gmt_create` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (`id`),
    KEY `idx_fq_numeric_adjustment_log_target` (`target_type`, `target_id`, `field_name`),
    KEY `idx_fq_numeric_adjustment_log_version` (`quote_version_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


