INSERT INTO `forwarder_quote_billing_rule` (
    `id`, `rule_code`, `quote_version_id`, `quote_version_code`, `service_code`, `cargo_category_code`, `rule_type`, `severity`, `condition_text`, `structured_field`, `operator`, `value`, `unit`, `action`, `volume_divisor`, `sea_weight_ratio`, `rounding_rule`, `max_length_cm`, `max_weight_kg`, `source_file_name`, `source_sheet_or_page`, `source_row_or_locator`, `source_type`, `remark`, `created_by`, `updated_by`
) VALUES
    (914001, 'RULE-0001', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'BILLING', 'SOFT', '1、沙特空运专线计费：体积重为长*宽*高除以5000（CM/KG），以实重与体积重取大者，保留小数点后两位计算（0.5进位）。单边不超1.5米，三边总和不超2米。', NULL, NULL, NULL, NULL, '加费/按规则处理', 5000, NULL, '保留小数点后两位；0.5进位', 150, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R13', 'file', NULL, 1, 1),
    (914002, 'RULE-0002', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'COMPENSATION', 'SOFT', '2、部分遗失，延误或者破损均不赔偿；货物丢失整箱赔偿：按照退运费赔偿1倍运费；敏货，易碎易破损不保价;货物经过查验导致丢失破损均不赔偿；', NULL, NULL, NULL, NULL, '加费/按规则处理', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R14', 'file', NULL, 1, 1),
    (914003, 'RULE-0003', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'PROHIBITED', 'HARD', '3、不接受产品：CCTV产品、品牌、纯电池、化妆品、电子烟、对讲机，以及粉末、易燃易爆，成人用品、药品、食品、保健品、精油等一经发现冲货，我司将向发货方追究责任!（点击查看违禁品清单）', NULL, NULL, NULL, NULL, '拒收/禁发', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R15', 'file', NULL, 1, 1),
    (914004, 'RULE-0004', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'PACKING', 'INFO', '4、客户需要提了解FBA/FBN的入仓要求，每个产品均有FBA/FBN特定条码标签，出货时请提供FBA/FBN入仓时所需的PO和装箱单、发票等完整的入仓资料。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R16', 'file', NULL, 1, 1),
    (914005, 'RULE-0005', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'PACKING', 'INFO', '5、因运输环节较多，请确保货物本身及包装的牢固性，易碎品破损或包装破损由寄件方负责。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R17', 'file', NULL, 1, 1),
    (914006, 'RULE-0006', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'INFO', 'INFO', '6、以上价格为含税报价，币种：RMB。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R18', 'file', NULL, 1, 1),
    (914007, 'RULE-0007', 904001, 'ZD-20260411', 'ZD-SAU-AIR-FBN-RUH', NULL, 'INFO', 'INFO', '7、请在交货清单注明对应的“销售产品名”', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特空运专线', 'R19', 'file', NULL, 1, 1),
    (914008, 'RULE-0008', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'COMPENSATION', 'INFO', '2、如果发生海关扣货，或者运输过程中不可控因素造成的货物丢失或损耗，本服务理赔规则按照合同协议内容执行。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R25', 'file', NULL, 1, 1),
    (914009, 'RULE-0009', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PACKING', 'HARD', '3、本服务不接任何与穆斯林宗教有冲突的产品（例如其他宗教信仰产品），不接任何色情用品，不接沙特海关禁止进口的产品，所以，交货前请提供清晰装箱单与及图片给我司相关人员确认。', NULL, NULL, NULL, NULL, '拒收/禁发', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R26', 'file', NULL, 1, 1),
    (914010, 'RULE-0010', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PACKING', 'INQUIRY', '4、本服务所接的产品都需要MADE IN CHINA 贴标或者洗水标，纺织品类需要洗水标MADE IN CHINA , 三C产品手机配件产品，则需要产品包装上有贴标或者包装盒自带印刷的MADE IN CHINA ,由于中国产品多样性，对于非常见产品具体MADE IN CHINA，以实际图片确认为准。', NULL, NULL, NULL, NULL, '人工确认', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R27', 'file', NULL, 1, 1),
    (914011, 'RULE-0011', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'BILLING', 'SOFT', '5、沙特海运计费：实重/300与材积/1000000相比，取大者；不足0.1立方，按照0.1立方计算。保留小数点后2位计算；如有木箱，托盘等包装收叉车费；', NULL, NULL, NULL, NULL, '加费/按规则处理', NULL, '1CBM=300KG', '保留小数点后2位；不足0.1立方，按照0.1立方', NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R28', 'file', NULL, 1, 1),
    (914012, 'RULE-0012', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'COMPENSATION', 'SOFT', '6、部分遗失，延误或者破损均不赔偿；货物丢失赔偿：按照退运费赔偿1倍运费，高价值物品建议购买保险。保险费是实际货值的3%，敏货，易碎易破损不保价。 / 发货前请自行告知是否需要购买保险及保险货值RMB。', NULL, NULL, NULL, NULL, '加费/按规则处理', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R29', 'file', NULL, 1, 1),
    (914013, 'RULE-0013', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PROHIBITED', 'HARD', '7、沙特违禁物品禁止出口，我司会进行抽箱查验，一经发现全部退回，若是违禁品在海关被扣所有责任应有客户承担。', NULL, NULL, NULL, NULL, '拒收/禁发', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R30', 'file', NULL, 1, 1),
    (914014, 'RULE-0014', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PROHIBITED', 'HARD', '8、仿牌货、违禁品，以及发票信息不准确的货物会被自动退回，因此所产生的后果及费用（含罚款）由寄件方自行承担。如因寄件方问题给我司造成重大损失，我司将保留追究寄件方责任的权利。', NULL, NULL, NULL, NULL, '拒收/禁发', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R31', 'file', NULL, 1, 1),
    (914015, 'RULE-0015', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'DECLARATION', 'SOFT', '9、寄件方必须提交海关通关所需的信息都是真实的、正确的、完整的文件，因而产生的海关罚款、储存费用、退运费用或其他费用由发货人承担。', NULL, NULL, NULL, NULL, '加费/按规则处理', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R32', 'file', NULL, 1, 1),
    (914016, 'RULE-0016', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PROHIBITED', 'HARD', '10、不接受产品：CCTV产品、品牌、纯电池、化妆品、电子烟、对讲机，以及粉末、易燃易爆，成人用品、药品、食品、保健品、精油等一经发现冲货，我司将向发货方追究责任!（点击查看违禁品清单）', NULL, NULL, NULL, NULL, '拒收/禁发', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R33', 'file', NULL, 1, 1),
    (914017, 'RULE-0017', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PACKING', 'INFO', '11、客户需要提了解FBA/FBN的入仓要求，每个产品均有FBA/FBN特定条码标签，出货时请提供FBA/FBN入仓时所需的PO和装箱单、发票等完整的入仓资料。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R34', 'file', NULL, 1, 1),
    (914018, 'RULE-0018', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'PACKING', 'INFO', '12、因运输环节较多，请确保货物本身及包装的牢固性，易碎品破损或包装破损由寄件方负责。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R35', 'file', NULL, 1, 1),
    (914019, 'RULE-0019', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'INFO', 'INFO', '13、以上价格为含税报价，币种：RMB。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R36', 'file', NULL, 1, 1),
    (914020, 'RULE-0020', 904001, 'ZD-20260411', 'ZD-SAU-SEA-WH-RUH', NULL, 'INFO', 'INQUIRY', '利雅得FBN/FBA：200RMB/立方；JED FBA另询价。', 'destination_city', '=', '利雅得/RUH', NULL, '人工确认', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海运专线', 'R24', 'file', NULL, 1, 1),
    (914021, 'RULE-0026', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'LABEL', 'INFO', '入仓要求：需在义特系统下单，并按要求贴上入仓标签（一箱2张，贴侧唛），每一个产品必须有made in china。', 'label_required', '=', 'made in china', NULL, '提示', NULL, NULL, NULL, NULL, NULL, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914022, 'RULE-0027', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'SIZE_WEIGHT', 'INFO', '包装要求：纸箱、编织袋、托盘、木架等不同包装均可；送平台仓（FBA/NOON）符合平台箱规尺寸（正常40*50*30）；单箱重量不超40公斤。', 'max_weight_kg', '<=', 40, 'KG', '提示', NULL, NULL, NULL, NULL, 40, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914023, 'RULE-0028', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'INFO', 'INQUIRY', 'FBA/FBN送仓：利亚德，吉达3RMB/KG，最低消费300RMB/票；大货类单询。', 'destination_city', '=', '利雅得/RUH', NULL, '人工确认', NULL, NULL, NULL, NULL, NULL, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914024, 'RULE-0029', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'SIZE_WEIGHT', 'INQUIRY', '箱规：单边尺寸超100CM以上的价格单询。', 'max_length_cm', '>', 100, 'CM', '人工确认', NULL, NULL, NULL, 100, NULL, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914025, 'RULE-0030', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'BILLING', 'HARD', '单证要求：低于10个方以下的货不接报关件（退税报关）；货重比1：300（1CBM=300KG）。', 'sea_weight_ratio', '=', '1CBM=300KG', NULL, '拒收/禁发', NULL, '1CBM=300KG', NULL, NULL, NULL, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914026, 'RULE-0031', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'PROHIBITED', 'HARD', '限制产品：不接液体、粉末、气体、食品、药品、酒和烟的任何相关产品等；不接宗教类产品：古兰经、成人情趣用品、电子烟、带激光类产品等；不接迷彩类、无人机、攻击性武器类产品。', NULL, NULL, NULL, NULL, '拒收/禁发', NULL, NULL, NULL, NULL, NULL, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914027, 'RULE-0032', 904002, 'YT-SAU-UNDATED-001', 'YT-SAU-SEA-FBN-RUH', NULL, 'INFO', 'INFO', '有插头产品：比如充电器，排插，家电类等产品，必须是英规三插。', 'plug_type', '=', '英规三插', NULL, '提示', NULL, NULL, NULL, NULL, NULL, '沙特价格表.pdf', 'PAGE 1', 'PDF text', 'file', NULL, 1, 1),
    (914028, 'RULE-0021', 904001, 'ZD-20260411', 'ZD-SAU-WH-PROCESS', NULL, 'LABEL', 'INQUIRY', '使用众鸫FBA/FBN空运物流专线整批入仓无需送仓费 / * 客户FBA/FBN送仓货物在海外仓备货： /    1.货物分批次送FBA/FBN仓库，海外仓会产生送仓费，仓储费，贴标签费 /    2.货物整批次送FBA/FBN仓库，海外仓会产生仓储费，贴标签费 / * 非众鸫原因单票货物多次送FBA/FBN仓库，送仓费需按次收取。 / * JED（吉达）FBA FBN 另询价', NULL, NULL, NULL, NULL, '人工确认', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海外仓服务', 'R15', 'file', NULL, 1, 1),
    (914029, 'RULE-0022', 904001, 'ZD-20260411', 'ZD-SAU-WH-PROCESS', NULL, 'SIZE_WEIGHT', 'SOFT', '按每个商品SKU / 未能匹配的货物将被视为“无人认领”，退货已被系统扫描并归入“无人认领”批次，后续若需找回，将收取20RMB/包裹专项处理费+1RMB/PCS退货上架； / “无人认领”仅保留2天，超出时间则默认销毁;退货操作链接：https://docs.qq.com/doc/DVmVVcWhZVW9CUmx6（如果链接打不开，找客服要一下）', NULL, NULL, NULL, NULL, '加费/按规则处理', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海外仓服务', 'R21', 'file', NULL, 1, 1),
    (914030, 'RULE-0023', 904001, 'ZD-20260411', 'ZD-SAU-WH-PROCESS', NULL, 'INFO', 'INFO', '1、众鸫沙特海外仓，专业服务于跨境电商客户，库存管理完善，发货精准，自有开发ERP系统进行管理，员工定期进行培训，立志于从海外仓管理及人工培训、系统化杜绝问题件的产生。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海外仓服务', 'R23', 'file', NULL, 1, 1),
    (914031, 'RULE-0024', 904001, 'ZD-20260411', 'ZD-SAU-WH-PROCESS', NULL, 'INFO', 'INFO', '2、众鸫供应链与沙特地区亚马逊/NOON有着深度的入仓渠道，我们可以为您通过亚马逊/NOON经理免预约绿色通道进行入仓。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海外仓服务', 'R24', 'file', NULL, 1, 1),
    (914032, 'RULE-0025', 904001, 'ZD-20260411', 'ZD-SAU-WH-PROCESS', NULL, 'INFO', 'INFO', '13、以上价格为含税报价，币种：RMB。', NULL, NULL, NULL, NULL, '提示', NULL, NULL, NULL, NULL, NULL, '深圳市众鸫供应链报价单2026.4.11(1)(2)(1).xlsx', '沙特海外仓服务', 'R25', 'file', NULL, 1, 1)
